#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=3e5+10;int P[N],p,t[N],a[N],n,Q,L,R,ans[N];struct Nd{int l,r,k,idx;}q[N];
inline void add(int x,int w){while(x<=p)t[x]+=w,x+=(x&-x);} 
inline int qry(int x){int res=0;while(x)res+=t[x],x^=(x&-x);return res;}
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
	n=read();rep(1,n,i)P[++p]=a[i]=read();Q=read();rep(1,Q,i){q[i].l=read();q[i].r=read();P[++p]=q[i].k=read();q[i].idx=i;}
	std::sort(P+1,P+p+1);p=std::unique(P+1,P+p+1)-P-1; rep(1,n,i)a[i]=p-bnd(a[i])+1;rep(1,Q,i)q[i].k=p-bnd(q[i].k);
	std::sort(q+1,q+Q+1,[&](const Nd&x,const Nd&y){return (x.l>>8)==(y.l>>8)?((x.l>>8)&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;rep(1,Q,i)
	{
		while(R<q[i].r)add(a[++R],1);while(L>q[i].l)add(a[--L],1);
		while(R>q[i].r)add(a[R--],-1);while(L<q[i].l)add(a[L++],-1);
		ans[q[i].idx]=q[i].k>p?0:qry(q[i].k);
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
